import{_ as i,e as a}from"./app.49cd7b53.js";const e={},s=a('<h1 id="\u52A0\u5BC6\u3001\u7B7E\u540D\u548C-ssl-\u63E1\u624B\u673A\u5236\u7EC6\u8282" tabindex="-1"><a class="header-anchor" href="#\u52A0\u5BC6\u3001\u7B7E\u540D\u548C-ssl-\u63E1\u624B\u673A\u5236\u7EC6\u8282" aria-hidden="true">#</a> \u52A0\u5BC6\u3001\u7B7E\u540D\u548C SSL \u63E1\u624B\u673A\u5236\u7EC6\u8282</h1><div class="custom-container tip"><p class="custom-container-title">\u4E92\u8054\u7F51\u6570\u636E\u5B89\u5168\u53EF\u9760\u7684\u6761\u4EF6\uFF1A</p><ul><li>\u6570\u636E\u6765\u6E90\u53EF\u4FE1\uFF0C\u5373\u6570\u636E\u53D1\u9001\u8005\u8EAB\u4EFD\u53EF\u4FE1\u3002</li><li>\u6570\u636E\u5177\u5907\u5B8C\u6574\u6027\uFF0C\u5373\u6570\u636E\u672A\u88AB\u4FEE\u6539\u8FC7\u3002</li><li>\u6570\u636E\u5B89\u5168\u6027\uFF0C\u5373\u6570\u636E\u4E0D\u4F1A\u88AB\u6CC4\u9732\uFF0C\u4ED6\u4EBA\u622A\u83B7\u540E\u65E0\u6CD5\u89E3\u5BC6\u3002</li></ul></div><p>\u6570\u636E\u5B89\u5168\u6027\u9700\u8981\u8FDB\u884C\u52A0\u5BC6\u89E3\u51B3\uFF0CAES \u5BF9\u79F0\u52A0\u5BC6\u6027\u80FD\u597D\uFF0C\u4F46\u662F\u9700\u8981\u53D1\u9001\u65B9\u548C\u63A5\u6536\u65B9\u90FD\u6709\u5BC6\u94A5\uFF0C\u975E\u5BF9\u79F0\u52A0\u5BC6 RSA \u4E0D\u9700\u8981\u53CC\u65B9\u90FD\u6709\u5BC6\u94A5\uFF0C\u4F46\u662F\u6027\u80FD\u5DEE\u3002\u4E00\u822C\u662F\u5148\u901A\u8FC7 RSA \u5EFA\u7ACB\u5B89\u5168\u7684\u8FDE\u63A5\uFF0C\u4F20\u8F93\u4E00\u4E2A\u968F\u673A\u7684 AES \u5BC6\u94A5\uFF0C\u7136\u540E\u540E\u7EED\u901A\u4FE1\u4F7F\u7528\u8FD9\u4E2A\u5BC6\u94A5\u8FDB\u884C AES \u52A0\u5BC6\u3002</p><p>\u4FDD\u8BC1\u4E86\u5B89\u5168\u6027\u4E4B\u540E\uFF0C\u8FD8\u9700\u8981\u4FDD\u8BC1\u6570\u636E\u7684\u5B8C\u6574\u6027\u3001\u4E00\u81F4\u6027\u4EE5\u53CA\u6570\u636E\u6765\u6E90\u7684\u53EF\u9760\u6027\u3002</p><p>\u5BF9\u4E8E\u6570\u636E\u7684\u5B8C\u6574\u6027\u548C\u4E00\u81F4\u6027\uFF0C\u4F7F\u7528\u5355\u5411\u52A0\u5BC6\u7B97\u6CD5\uFF0C\u5373\u54C8\u5E0C\u51FD\u6570\uFF0C\u8BA1\u7B97\u51FA\u72EC\u4E00\u65E0\u4E8C\u7684\u6821\u9A8C\u7801\uFF0C\u8FD9\u4E2A\u6821\u9A8C\u7801\u79F0\u4E3A<strong>\u4FE1\u606F\u6458\u8981\uFF08Message Digest\uFF09</strong>\u3002</p><p>\u5BF9\u4E8E\u6570\u636E\u6765\u6E90\u7684\u53EF\u9760\u6027\uFF0C\u53D1\u9001\u65B9\u5728\u53D1\u9001\u65F6\u5148\u7528\u81EA\u5DF1\u7684\u79C1\u94A5\u52A0\u5BC6\uFF0C\u5982\u679C\u63A5\u6536\u65B9\u65E0\u6CD5\u4F7F\u7528\u53D1\u9001\u65B9\u7684\u516C\u94A5\u89E3\u5BC6\u5C31\u8868\u793A\u6570\u636E\u6765\u6E90\u5B58\u5728\u95EE\u9898\u3002\u7531\u4E8E RSA \u6027\u80FD\u8F83\u5DEE\uFF0C\u6240\u4EE5\u53EF\u4EE5\u53EA\u4F7F\u7528\u79C1\u94A5\u52A0\u5BC6\u4E0A\u9762\u7684\u4FE1\u606F\u6458\u8981\uFF0C\u52A0\u5BC6\u540E\u7684\u6458\u8981\u4FE1\u606F\u79F0\u4E3A<strong>\u6570\u5B57\u7B7E\u540D</strong>\u3002</p><p>\u63A5\u6536\u65B9\u83B7\u53D6\u5230\u6570\u636E\u540E\uFF0C\u4F7F\u7528\u53D1\u9001\u65B9\u7684\u516C\u94A5\u89E3\u5BC6\uFF0C\u5982\u679C\u89E3\u5BC6\u5931\u8D25\u5219\u8868\u793A\u6570\u636E\u6765\u6E90\u6709\u95EE\u9898\uFF0C\u5982\u679C\u6CA1\u6709\u95EE\u9898\u8BF4\u660E\u6570\u636E\u6765\u6E90\u53EF\u9760\u3002\u8FD9\u65F6\u63A5\u6536\u65B9\u53EF\u4EE5\u4F7F\u7528\u540C\u6837\u7684\u54C8\u5E0C\u7B97\u6CD5\u83B7\u53D6\u6458\u8981\u4FE1\u606F\uFF0C\u5C06\u81EA\u5DF1\u8BA1\u7B97\u5F97\u5230\u7684\u6458\u8981\u4FE1\u606F\u548C\u6536\u5230\u7684\u6458\u8981\u4FE1\u606F\u8FDB\u884C\u6BD4\u5BF9\uFF0C\u5982\u679C\u76F8\u7B49\u5C31\u8BF4\u660E\u6570\u636E\u6CA1\u6709\u88AB\u4FEE\u6539\u8FC7\uFF0C\u5426\u5219\u5C31\u662F\u88AB\u4FEE\u6539\u8FC7\u4E86\u3002</p><h2 id="ca\u3001pki-\u53CA\u4FE1\u4EFB-ca" tabindex="-1"><a class="header-anchor" href="#ca\u3001pki-\u53CA\u4FE1\u4EFB-ca" aria-hidden="true">#</a> CA\u3001PKI \u53CA\u4FE1\u4EFB CA</h2><p>CA \u662F\u6570\u5B57\u8BC1\u4E66\u8BA4\u8BC1\u4E2D\u5FC3\uFF0C\u5E38\u79F0\u4E3A\u8BC1\u4E66\u9881\u53D1\u673A\u6784\uFF0C\u7533\u8BF7\u8005\u63D0\u4EA4\u81EA\u5DF1\u7684\u516C\u94A5\u548C\u4E00\u4E9B\u4E2A\u4EBA\u4FE1\u606F\u7ED9 CA\uFF0CCA \u5BF9\u7533\u8BF7\u8005\u7684\u8FD9\u4E9B\u4FE1\u606F\u5355\u5411\u52A0\u5BC6\u751F\u6210\u6458\u8981\u4FE1\u606F\uFF0C\u7136\u540E\u4F7F\u7528\u81EA\u5DF1\u7684\u79C1\u94A5\u52A0\u5BC6\u6574\u4E2A\u6458\u8981\u4FE1\u606F\uFF0C\u8FD9\u6837\u5C31\u5F97\u5230\u4E86 CA \u5BF9\u7533\u8BF7\u8005\u7684\u6570\u5B57\u7B7E\u540D\uFF0C\u5728\u6570\u5B57\u7B7E\u540D\u4E0A\u518D\u52A0\u4E0A CA \u81EA\u5DF1\u7684\u4E00\u4E9B\u4FE1\u606F\u53CA\u8BE5\u8BC1\u4E66\u7684\u4FE1\u606F\u5C31\u5F97\u5230\u4E86\u6570\u5B57\u8BC1\u4E66\u3002</p><p>\u5982\u679C\u67D0\u7528\u6237\u4FE1\u4EFB\u4E86\u8BE5 CA\uFF0C\u5C31\u83B7\u53D6\u4E86\u8BE5 CA \u7684\u516C\u94A5\uFF0C\u4F7F\u7528\u8BE5\u516C\u94A5\u89E3\u5BC6\u6570\u5B57\u8BC1\u4E66\u5C31\u53EF\u4EE5\u9A8C\u8BC1\u7533\u8BF7\u8005\u7684\u4FE1\u606F\u4EE5\u53CA\u7533\u8BF7\u8005\u516C\u94A5\u7684\u53EF\u9760\u6027\u3002</p><p>CA \u5982\u4F55\u4FDD\u8BC1\u81EA\u8EAB\u7684\u5408\u6CD5\u6027\u5462\uFF1F\u6839 CA \u662F\u901A\u8FC7\u81EA\u7B7E\u7F72\u6570\u5B57\u8BC1\u4E66\u7684\u65B9\u5F0F\u6807\u699C\u81EA\u5DF1\u7684\u53EF\u4FE1\u6027\u548C\u5408\u6CD5\u6027\uFF0C\u7B2C\u4E00\u7EA7\u5B50 CA \u7531\u6839 CA \u9881\u53D1\u5408\u6CD5\u6570\u5B57\u8BC1\u4E66\uFF0C\u7B2C\u4E8C\u7EA7\u81F3\u6240\u6709\u7684\u5B50 CA \u90FD\u7531\u4E0A\u4E00\u7EA7\u5B50 CA \u9881\u53D1\u6570\u5B57\u8BC1\u4E66\uFF0C\u5BF9\u4E8E\u591A\u7EA7\u5B50 CA \u53EA\u9700\u8981\u4FE1\u4EFB\u6839 CA \u5373\u53EF\uFF0C\u56E0\u4E3A\u83B7\u5F97\u4E86\u6839 CA \u7684\u516C\u94A5\uFF0C\u53EF\u4EE5\u89E3\u5BC6\u7B2C\u4E00\u7EA7\u5B50 CA \u7684\u8BC1\u4E66\u5E76\u83B7\u53D6\u9A8C\u8BC1\u7B2C\u4E00\u7EA7\u5B50 CA \u7684\u516C\u94A5\uFF0C\u5C42\u5C42\u9012\u8FDB\uFF0C\u6700\u7EC8\u83B7\u53D6\u5230\u4E3A\u7533\u8BF7\u8005\u9881\u53D1\u6570\u5B57\u8BC1\u4E66\u7684\u673A\u6784\u5E76\u83B7\u53D6\u5B83\u7684\u516C\u94A5\u3002</p><p>\u53E6\u4E00\u79CD\u60C5\u51B5\uFF0C\u867D\u7136\u4FE1\u4EFB\u4E86\u6839 CA\uFF0C\u4F46\u662F\u5982\u679C\u6839 CA \u6388\u6743\u7684\u67D0\u4E2A\u4E8C\u7EA7\u6216\u8005\u66F4\u4F4E\u7EA7\u7684 CA \u4E0D\u518D\u4FE1\u4EFB\u5217\u8868\u4E2D\uFF0C\u5C31\u9700\u8981\u5C06\u8FD9\u4E2A\u4E2D\u95F4\u7684 CA \u8865\u9F50\uFF0C\u5426\u5219\u4E2D\u95F4\u51FA\u73B0\u65AD\u5C42\u3002\u901A\u5E38\u8FD9\u79CD\u4E2D\u95F4 CA \u7684\u8BC1\u4E66\u79F0\u4E3A chain \u8BC1\u4E66\uFF0C\u5982\u679C\u8D2D\u4E70\u7684\u8BC1\u4E66\u5305\u542B chain.crt \u6587\u4EF6\u5C31\u8BF4\u660E\u5B83\u662F\u4E2D\u95F4 CA\uFF0C\u8FD9\u662F\u5E94\u8BE5\u5C06\u8FD9\u4E2A chain \u8BC1\u4E66\u4E5F\u90E8\u7F72\u5230\u670D\u52A1\u5668\u4E0A\u3002</p><p>\u6839 CA \u548C\u5B50 CA \u6784\u6210\u4E86 PKI\u3002</p><p>\u4FE1\u4EFBCA\u540E\uFF0C\u6BCF\u6B21\u63A5\u6536\u5230\u9700\u8981\u89E3\u5BC6\u7684\u6570\u5B57\u8BC1\u4E66\u65F6\uFF0C\u8FD8\u8981\u53BB\u8BE5\u9881\u53D1\u673A\u6784\u6307\u5B9A\u7F51\u7AD9\u7684\u8BC1\u4E66\u540A\u9500\u5217\u8868\uFF08CRL\uFF09\u4E2D\u67E5\u8BE2\u8BE5\u8BC1\u4E66\u662F\u5426\u88AB\u540A\u9500\uFF0C\u5BF9\u4E8E\u540A\u9500\u540E\u7684\u8BC1\u4E66\u5E94\u8BE5\u4E0D\u4E88\u4EE5\u4FE1\u4EFB\uFF0C\u8FD9\u662F\u4FE1\u4EFBCA\u7684\u7B2C\u4E8C\u4E2A\u4F5C\u7528\u3002\u5BFC\u81F4\u8BC1\u4E66\u88AB\u540A\u9500\u7684\u53EF\u80FD\u6027\u4E0D\u5C11\uFF0C\u4F8B\u5982\u7533\u8BF7\u8005\u7684\u79C1\u94A5\u88AB\u9ED1\u5BA2\u83B7\u53D6\uFF0C\u7533\u8BF7\u8005\u7533\u8BF7\u540A\u9500\u7B49\u3002</p><p>\u4E5F\u6709\u516C\u53F8\u4F7F\u7528\u81EA\u7B7E\u7684\u8BC1\u4E66\uFF0C\u4F8B\u5982\u67D0\u4E9B\u94F6\u884C\u300112306\u6709\u65F6\u5019\u5C31\u8981\u6C42\u4E0B\u8F7D\u8BC1\u4E66\u5E76\u5B89\u88C5\u3002\u65B9\u4FBF\u3001\u7701\u94B1\u3002</p><h2 id="\u6570\u5B57\u8BC1\u4E66\u7684\u7C7B\u578B\u548C\u5185\u5BB9" tabindex="-1"><a class="header-anchor" href="#\u6570\u5B57\u8BC1\u4E66\u7684\u7C7B\u578B\u548C\u5185\u5BB9" aria-hidden="true">#</a> \u6570\u5B57\u8BC1\u4E66\u7684\u7C7B\u578B\u548C\u5185\u5BB9</h2><p>PKI \u7684\u4E24\u79CD\u5B9E\u73B0\u65B9\u5F0F TLS \u548C SSL \u4F7F\u7528\u7684\u8BC1\u4E66\u683C\u5F0F\u90FD\u662F x509\uFF0CTLSv1 \u548C SSLv3 \u57FA\u672C\u7B49\u4EF7\uFF0C\u53EA\u4E0D\u8FC7 SSL \u5B9E\u73B0\u5728 OSI 4 \u5C42\u6A21\u578B\u4E2D\u7684\u5E94\u7528\u5C42\u548C\u4F20\u8F93\u5C42\u7684\u4E2D\u95F4\uFF0CTLS \u5B9E\u73B0\u5728\u4F20\u8F93\u5C42\u3002</p><p>\u8FD8\u6709 PKI \u7684\u53E6\u4E00\u79CD\u5B9E\u73B0\u65B9\u5F0F GPG\uFF0C\u5B83\u7684\u8BC1\u4E66\u4F7F\u7528\u7684\u4E0D\u662F x509 \u683C\u5F0F\u3002</p><p>\u6570\u5B57\u8BC1\u4E66\u4E2D\u5305\u542B\u7684\u4FE1\u606F\u6709\uFF1A\u7533\u8BF7\u8005\u7684\u516C\u94A5\uFF0C\u8BC1\u4E66\u6709\u6548\u671F\uFF0C\u8BC1\u4E66\u5408\u6CD5\u62E5\u6709\u4EBA\uFF0C\u8BC1\u4E66\u5982\u4F55\u88AB\u4F7F\u7528\uFF0CCA \u7684\u4FE1\u606F\uFF0CCA \u5BF9\u7533\u8BF7\u8005\u4FE1\u606F\u7684\u6570\u5B57\u7B7E\u540D\u3002</p><h2 id="ssl-\u63E1\u624B\u673A\u5236" tabindex="-1"><a class="header-anchor" href="#ssl-\u63E1\u624B\u673A\u5236" aria-hidden="true">#</a> SSL \u63E1\u624B\u673A\u5236</h2><ul><li>\u5BA2\u6237\u7AEF\u7ED9\u51FA\u534F\u8BAE\u7248\u672C\u53F7\uFF0C\u4E00\u4E2A\u5BA2\u6237\u7AEF\u968F\u673A\u6570\uFF0C\u4EE5\u53CA\u5BA2\u6237\u7AEF\u652F\u6301\u7684\u52A0\u5BC6\u65B9\u5F0F\u3002</li><li>\u670D\u52A1\u7AEF\u786E\u8BA4\u53CC\u65B9\u4F7F\u7528\u7684\u52A0\u5BC6\u65B9\u6CD5\uFF0C\u4EE5\u53CA\u4E00\u4E2A\u670D\u52A1\u5668\u751F\u6210\u7684\u968F\u673A\u6570\u3002</li><li>\u670D\u52A1\u5668\u5C06\u6570\u5B57\u8BC1\u4E66\u53D1\u9001\u7ED9\u5BA2\u6237\u7AEF\u3002</li><li>\u5BA2\u6237\u7AEF\u786E\u8BA4\u6570\u5B57\u8BC1\u4E66\u6709\u6548\uFF08\u67E5\u770B\u8BC1\u4E66\u72B6\u6001\u5E76\u67E5\u8BE2\u8BC1\u4E66\u540A\u9500\u5217\u8868\uFF09\uFF0C\u5E76\u4F7F\u7528\u4FE1\u4EFB\u7684 CA \u7684\u516C\u94A5\u89E3\u5BC6\u6570\u5B57\u8BC1\u4E66\u83B7\u5F97\u670D\u52A1\u7AEF\u7684\u516C\u94A5\uFF0C\u7136\u540E\u751F\u6210\u4E00\u4E2A\u65B0\u7684 46 \u5B57\u8282\u968F\u673A\u6570\uFF08\u79F0\u4E3A\u9884\u5907\u4E3B\u5BC6\u94A5\uFF09\u5E76\u4F7F\u7528\u670D\u52A1\u7AEF\u7684\u516C\u94A5\u52A0\u5BC6\u9884\u5907\u4E3B\u5BC6\u94A5\u53D1\u9001\u7ED9\u670D\u52A1\u7AEF\u3002</li><li>\u670D\u52A1\u7AEF\u4F7F\u7528\u81EA\u5DF1\u7684\u79C1\u94A5\u89E3\u5BC6\u53D1\u6765\u7684\u9884\u5907\u4E3B\u5BC6\u94A5\u3002</li><li>\u5BA2\u6237\u7AEF\u548C\u670D\u52A1\u7AEF\u53CC\u65B9\u90FD\u5177\u6709\u4E86\u5BA2\u6237\u7AEF\u968F\u673A\u6570\u3001\u670D\u52A1\u7AEF\u968F\u673A\u6570\u3001\u9884\u5907\u4E3B\u5BC6\u94A5\uFF0C\u4E8C\u8005\u6839\u636E\u7EA6\u5B9A\u7684\u52A0\u5BC6\u65B9\u6CD5\u4F7F\u7528\u8FD9\u4E09\u4E2A\u968F\u673A\u6570\u751F\u6210\u5BF9\u79F0\u5BC6\u94A5\u2014\u2014\u4E3B\u5BC6\u94A5\uFF08\u4E5F\u6210\u5BF9\u8BDD\u5BC6\u94A5\uFF09\uFF0C\u7528\u6765\u52A0\u5BC6\u63A5\u4E0B\u6765\u7684\u6574\u4E2A\u5BF9\u8BDD\u8FC7\u7A0B\u3002</li><li>\u5728\u53CC\u65B9\u9A8C\u8BC1\u73A9\u4E3B\u5BC6\u94A5\u7684\u6709\u6548\u6027\u4E4B\u540E\uFF0CSSL \u63E1\u624B\u673A\u5236\u5C31\u7ED3\u675F\u4E86\uFF0C\u4E4B\u540E\u6240\u6709\u7684\u6570\u636E\u901A\u8FC7\u4E3B\u5BC6\u94A5\u52A0\u5BC6\u4F20\u8F93\u5373\u53EF\u3002</li></ul>',21);function l(r,A){return s}var t=i(e,[["render",l],["__file","basic.html.vue"]]);export{t as default};
